const RETRIES_NUM = 3;
const RETRIES_INTERVAL = 1000;

const init_msg = {};

const {
    Configuration,
    ConfigurationApi,
} = humanAiBenchmarkSuite;

const isEmpty = (obj) => {
    for (const prop in obj) {
        if (Object.hasOwn(obj, prop)) {
            return false;
        }
    }
    return true;
};

const delay = (time) => {
    return new Promise(res => {
        setTimeout(res, time);
    })
};

const retryWithDelay = async (fn, retries = 3, interval = 100) => {
    try {
        return await fn();
    } catch (err) {
        if (retries <= 0) throw err;
        await delay(interval);
        return retryWithDelay(fn, retries - 1, interval);
    }
};

const haic_setup = async (ip, port, username, password, options, use_https = true) => {
    const scheme = use_https ? 'https://' : "http://";

    const configParams = {
        basePath: `${scheme}${ip}:${port}`,
    };

    if (username && password) {
        configParams.username = username;
        configParams.password = password;
    }

    if (!isEmpty(options)) {
        configParams.options = options;
    }

    const config = new Configuration(configParams);
    const testClient = new ConfigurationApi(config);
    let response = null;
    let err_msg = null;

    try {
        response = await retryWithDelay(
            // A test call, given the complete HAIC API client instance.
            async () => {
               await testClient.getAllConfigurationsConfigurationListGet();
            },
            RETRIES_NUM,
            RETRIES_INTERVAL,
        );
    } catch (err) {
        err_msg = `Failed to connect to HAIC Benchmarking Suite! Configuration must be invalid! ${err}`;
        node.error(err_msg);
    }

    return {
        "clientConfig": config,
        "testResponse": response,
        "error": err_msg
    };


};

context.set(
    "haic_setup",
    haic_setup
);

const {
    clientConfig,
    testResponse,
    error,
} = await haic_setup(
    env.get("IP Address"),
    env.get("Port"),
    env.get("Username"),
    env.get("Password"),
    env.get("Options"),
    env.get("Use HTTPS")
);

if (error == null) {
    // Successful setup
    init_msg.HaicApiClientConfiguration = clientConfig;
    init_msg.payload = "HAIC Client Configuration setup successful!";
    init_msg.HaicTestCallOutput = testResponse;
    init_msg.humanAiBenchmarkSuite = humanAiBenchmarkSuite;
    init_msg.useGlobally = env.get("Use Globally");

    node.send([init_msg, null]);
} else {
    // Error during setup
    init_msg.payload = error;
    init_msg.error = error;
    init_msg.humanAiBenchmarkSuite = humanAiBenchmarkSuite;
    init_msg.FailedHaicApiClientConfiguration = clientConfig;

    node.send([null, init_msg]);
}

