// CONSTANTS FOR THE UTILITY FUNCTIONS
const RETRIES_NUM = 3;
const RETRIES_INTERVAL = 1000;


// GENERIC UTILITY FUNCTIONS ------------------


const isEmpty = (obj) => {
    for (const prop in obj) {
        if (Object.hasOwn(obj, prop)) {
            return false;
        }
    }
    return true;
};

const mergeObjects = (a, b) => ({
    ...((a ?? {}) || {}),
    ...((b ?? {}) || {})
});

const delay = (time) => {
    return new Promise(res => {
        setTimeout(res, time);
    })
};

const retryWithDelay = async (fn, retries = RETRIES_NUM, interval = RETRIES_INTERVAL) => {
    try {
        return await fn();
    } catch (err) {
        if (retries <= 0) throw err;
        await delay(interval);
        return retryWithDelay(fn, retries - 1, interval);
    }
};



// Client-Specific utility functions ---------

const processResponse = (clientResponseObj) => {

    if (clientResponseObj.status >= 200 || clientResponseObj.status < 300) {
        return {
            clientResponse: clientResponseObj,
            responseData: clientResponseObj.data,
        }
    } else {
        return {
            errorData: clientResponseObj.data,
            clientResponse: clientResponseObj,
        }
    }

};


// HAIC-Specific utility functions -----------

const getHaicFunctions = (flowObj, globalObj, nodeObj) => {
    const CONFIG_ERROR_MSG = "HAIC API CLIENT CONNECTION NOT CONFIGURED PROPERLY!";
    let clientFunctions = flowObj.get("$parent.HaicApiClients");
    if (!clientFunctions) {
        clientFunctions = globalObj.get("HaicApiClients");
    }
    if (!clientFunctions) {
        // If not found in either, throw an error and halt the flow
        nodeObj.error(CONFIG_ERROR_MSG, msg);
        nodeObj.send([null, {
            error: CONFIG_ERROR_MSG
        }]);
        return;
    }
    return clientFunctions;
};


// FUNCTIONS MAP TO ALWAYS SET GLOBALLY
const globalUtilFunctions = {
    // ALL GLOBALLY AVALIABLE FUNCTIONS HERE:
    "getHaicFunctions": getHaicFunctions,
};
// Add/Update global utilities
global.set("globalUtilFunctions",
    mergeObjects(
        global.get("globalUtilFunctions"), globalUtilFunctions
    )
);



// FUNCTIONS MAP TO SET UP WHEREVER USER CHOSE
const utilFunctions = {
    // ALL EXPORTED FUNCTIONS HERE:
    "isEmpty": isEmpty,
    "delay": delay,
    "retryWithDelay": retryWithDelay,
    "processResponse": processResponse,
};


// SET FUNCTIONS TO APPROPRIATE CONTEXT

if (msg.useGlobally) {
    global.set("HaicApiClientUtils", utilFunctions);
    context.set("useGlobally", true);
} else {
    // Sets on the context of the "parent" flow, where this subflow is instantiated.
    flow.set("$parent.HaicApiClientUtils", utilFunctions);
    context.set("useGlobally", false);
}

msg.HaicApiClientUtils = utilFunctions;
return msg;

