// Import all client classes
const {
    ConfigurationApi,
    DefaultApi,
    EvaluationApi,
    LogGeneratorApi,
    LogsApi,
    ReportingApi,
    ResultsApi,
    SurveyApi,
} = humanAiBenchmarkSuite;
const haicClasses = {
    ConfigurationApi,
    DefaultApi,
    EvaluationApi,
    LogGeneratorApi,
    LogsApi,
    ReportingApi,
    ResultsApi,
    SurveyApi,
}
// Import config and utils
const config = msg.HaicApiClientConfiguration;
const utils = msg.HaicApiClientUtils;
const retryWithDelay = utils.retryWithDelay;
const processResponse = utils.processResponse;

// ALL CLIENTS AND THE FUNCTIONS SET UP HERE
const httpMethods = ['Get', 'Put', 'Post', 'Delete'];
// Mapping: API Section -> Operation -> Function that does it
const haicApiClients = {};

for (const [originalClassName, ClassConstructor] of Object.entries(haicClasses)) {
  const className = originalClassName.endsWith('Api')
    ? originalClassName.slice(0, -3)
    : originalClassName;

  // ALL CLIENTS GET THE CONFIG HERE
  const instance = new ClassConstructor(config);

  const methodNames = Object.getOwnPropertyNames(ClassConstructor.prototype)
    .filter(name => name !== 'constructor');

  const filteredMethods = methodNames.filter(name =>
    httpMethods.some(verb => name.endsWith(verb))
  );

  const haicApiWrappers = {};

  filteredMethods.forEach(methodName => {
    haicApiWrappers[methodName] = async function (...args) {
      // --- Custom logic BEFORE calling the original async method ---
      // console.log(`Calling async ${className}.${methodName} with arguments:`, args); //TEST
      // const start = Date.now(); //TEST
      console.log("ARGUMENTS", args);

      try {
        // Await the async method call
        const result = await retryWithDelay(
          async () => {
            return processResponse(await instance[methodName](...args));
          }
        );

        // --- Custom logic AFTER the async method resolves ---
        // const duration = Date.now() - start; // TEST
        // console.log(`Result from async ${className}.${methodName} (took ${duration}ms):`, result); //TEST

        // Return the awaited result (or a modified version)
        return result;
      } catch (error) {
        console.error(`Error in async ${className}.${methodName}:`, error);
        throw error; // re-throw or handle error as needed
      }
    };
  });

  haicApiClients[className] = haicApiWrappers;
}

// console.log(haicApiClients); // TEST


// SET THE CLIENTS TO THE APPROPRIATE CONTEXT
if(msg.useGlobally) {
    global.set("HaicApiClients", haicApiClients);
    context.set("useGlobally", true);
} else {
    // Sets on the context of the "parent" flow, where this subflow is instantiated.
    flow.set("$parent.HaicApiClients", haicApiClients);
    context.set("useGlobally", false);
}

