function createDateStepper(initialISODate) {
  let currentDate = new Date(initialISODate);

  if (isNaN(currentDate)) {
    throw new Error("Invalid initial ISO date format");
  }

  return function step(days = 0, hours = 0) {
    // Convert time steps to milliseconds for precise calculations
    const msToAdd = (days * 86400000) + (hours * 3600000);
    currentDate = new Date(currentDate.getTime() + msToAdd);
    return currentDate.toISOString();
  };
}

